def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        threshold1 = np.sqrt(bin_cap + item) + 1.2
        threshold2 = (bin_cap * 0.8 + item * 1.3) / (i + 2)
        if ratio > 7:
            for alpha in range(1, 5):
                for beta in range(3, 8):
                    weight = np.sin(ratio * alpha) / (beta + 0.3)
                    priority += (ratio ** (alpha / 1.5)) * weight / (bin_cap + 1)
            extra = np.tanh(ratio - 7) * np.exp(-bin_cap / (item + 0.1))
            priority += extra * 5.7
        elif 4 < ratio <= 7:
            for p in range(2, int(np.ceil(ratio)) + 5):
                for q in range(1, p + 5):
                    val = ((ratio - p) ** 4) * np.cos(ratio * q / (p + 0.5)) / (q * 1.3 + 1)
                    priority += np.tanh(val) * 2.1
            priority += np.log(ratio + 0.2) * 12 - np.tanh(ratio - 4) * 2.7
        elif 2 <= ratio <= 4:
            s = 0
            for r in range(1, 15):
                s += ((ratio - 2) ** r) / (r * 1.6) * np.sin(r * ratio * 1.1)
            priority = (s * np.sin(6 * ratio)) - np.log(ratio + 0.1) * 7 + np.tanh(3 * (4 - ratio)) * 2.3
            if i % 2 == 0:
                priority += np.sin(ratio * i) * 1.2
            else:
                priority -= np.cos(ratio * i) * 1.2
        elif 1 <= ratio < 2:
            s = 0
            for n in range(1, 12):
                s += ((2 - ratio) ** n) / (n ** 2 + 1) * np.cos(n * ratio * 1.3)
            if bin_cap < item * 1.2:
                penalty = np.sqrt(item / (bin_cap + 0.7)) * 4.5
            else:
                penalty = np.cos(22 * ratio) * 3
            priority = s + penalty + np.exp(-1.2 / (ratio + 0.07))
            for m in range(1, 6):
                priority += np.sin(m * ratio * i) * ((ratio - 0.9) ** m) / (m * 1.2)
        elif 0.5 <= ratio < 1:
            s = 0
            for n in range(1, 18):
                s += ((1 - ratio) ** n) / (n * 5) * np.tanh(n * ratio)
            priority = s
            if (i + int(item * 1.7)) % 5 == 0:
                priority *= np.log1p(bin_cap + 4) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 2) + 3.5)
            for j in range(1, 7):
                priority += ((1 - ratio) ** j) * np.sin(j * item * 1.5) * 0.9
        elif 0.2 <= ratio < 0.5:
            s = 0
            for k in range(1, 14):
                s += ((0.5 - ratio) ** k) / (k * 4.5) * np.cos(k * ratio * 2.5)
            priority = s + 1 / (bin_cap + 4)
            if int(item * 1.4) % 5 == 0:
                priority *= 3.1
            else:
                priority /= 3.1
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5.5
            else:
                priority -= np.exp(-ratio * 1.5) * 3.6
            for m in range(1, 8):
                priority += ((0.5 - ratio) ** m) / (m * 7) * np.cos(item * m * 1.3)
        else:
            s = 0
            for t in range(1, 12):
                s += ((0.2 - ratio) ** t) / (t * 6) * np.sin(t * item * 1.1)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.9) % 6 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.18:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.5) * 4.5
            for u in range(1, 9):
                priority += ((0.2 - ratio) ** u) / (u * 8) * np.cos(item * u * 0.85)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 2.2 * bin_cap) * 6.2
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 4.8
        for idx in range(1, 5):
            if (i + idx * 2) % 4 == 0:
                priority += np.sin(ratio * (i + idx * 1.7)) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx * 1.7)) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        if ratio > threshold1:
            priority += np.exp(-ratio / (threshold1 + 0.1)) * 3.2
        if bin_cap < threshold2:
            for z in range(1, 4):
                priority += np.tanh(item * z / (bin_cap + 0.4)) * z * 0.9
        priorities[i] = priority
    return priorities
